function getValue(obj, keys, defaultValue = '') {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null) {
      return obj[key];
    }
  }
  return defaultValue;
}

function commentsToText(commentaires) {
  if (!commentaires) return '';
  if (Array.isArray(commentaires)) {
    return commentaires.map((c, i) => `Commentaire ${i + 1} : ${c.contenu || c.text || ''}`).join('\n');
  }
  if (typeof commentaires === 'object') {
    return Object.entries(commentaires).map(([k, v]) => `${k} : ${v.contenu || v.text || ''}`).join('\n');
  }
  return String(commentaires);
}

function cleanForKeywords(text) {
  return String(text || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function buildKeywords(resume, description) {
  const stopwords = new Set([
    // Clés techniques n8n / structure JSON
    'comment1', 'comment2', 'comment3', 'comment4', 'comment5',
    'comment6', 'comment7', 'comment8', 'comment9', 'comment10',

    // Pronoms et déterminants
    'le', 'la', 'les', 'un', 'une', 'des', 'du', 'au', 'aux',
    'mon', 'ton', 'son', 'notre', 'votre', 'leur', 'leurs',
    'moi', 'toi', 'lui', 'eux', 'elle', 'elles', 'nous', 'vous',
    'ce', 'cet', 'cette', 'ces', 'cela', 'ceci', 'ca',
    'qui', 'que', 'quoi', 'dont', 'ou', 'quel', 'quelle', 'quels', 'quelles',

    // Prépositions et conjonctions
    'avec', 'dans', 'pour', 'par', 'sur', 'sous', 'entre', 'vers', 'chez',
    'sans', 'selon', 'depuis', 'avant', 'apres', 'pendant', 'contre',
    'mais', 'donc', 'alors', 'ainsi', 'aussi', 'comme', 'car', 'ni', 'or',
    'et', 'ou', 'si', 'que', 'quand', 'lorsque', 'puisque', 'quoique',

    // Verbes courants conjugués
    'est', 'sont', 'etait', 'etaient', 'sera', 'seront', 'soit',
    'avoir', 'etre', 'suis', 'avez', 'avons', 'ont', 'avait', 'avaient',
    'faire', 'fait', 'faites', 'fais', 'faisant',
    'aller', 'vais', 'allez', 'allons', 'allait',
    'voir', 'vois', 'voyez', 'voyons',
    'dire', 'dis', 'dites', 'disons',
    'pouvoir', 'peux', 'peut', 'pouvez', 'pouvons', 'pouvait',
    'vouloir', 'veux', 'veut', 'voulez', 'voulons',
    'devoir', 'dois', 'doit', 'devez', 'devons', 'devait',
    'prendre', 'prends', 'prend', 'prenez', 'prenons',
    'mettre', 'mets', 'met', 'mettez', 'mettons',
    'lance', 'lancer', 'affiche', 'afficher', 'bloque', 'bloquer',
    'arrete', 'arreter', 'ouvrir', 'ouvre', 'ouvrez',
    'recevoir', 'recois', 'recoit', 'recevez',
    'valider', 'valide', 'validez', 'valide',
    'afficher', 'affiche', 'affichage',
    'installer', 'installe', 'installez',
    'redemarrer', 'redemarrage', 'redemarre',
    'connecter', 'connecte', 'connectez', 'connexion',

    // Adverbes courants
    'tres', 'plus', 'moins', 'bien', 'mal', 'mieux', 'encore',
    'toujours', 'jamais', 'souvent', 'parfois', 'rarement',
    'ici', 'la', 'voici', 'voila', 'maintenant', 'puis', 'ensuite',
    'deja', 'enfin', 'seulement', 'aussi', 'donc', 'pourtant',
    'cependant', 'toutefois', 'neanmoins', 'sinon',

    // Mots IT génériques
    'ticket', 'probleme', 'erreur', 'issue', 'incident', 'demande',
    'utilisateur', 'user', 'client', 'agent', 'technicien',
    'application', 'logiciel', 'systeme', 'service',
    'message', 'notification', 'alerte', 'fenetre', 'ecran',
    'acces', 'droit', 'permission', 'profil', 'compte', 'session',
    'reseau', 'internet', 'connexion', 'poste', 'ordinateur', 'machine',
    'support', 'aide', 'assistance', 'helpdesk',
    'bonjour', 'merci', 'cordialement', 'bonne', 'journee', 'bonsoir',
    'resolution', 'resolu', 'ferme', 'termine', 'clos', 'ouvert',
    'statut', 'priorite', 'urgent', 'normal', 'faible',

    // Temporel
    'aujourd', 'hui', 'hier', 'demain', 'matin', 'soir', 'midi',
    'lundi', 'mardi', 'mercredi', 'jeudi', 'vendredi', 'samedi', 'dimanche',
    'janvier', 'fevrier', 'mars', 'avril', 'mai', 'juin',
    'juillet', 'aout', 'septembre', 'octobre', 'novembre', 'decembre',
    'semaine', 'mois', 'annee', 'heure', 'minute', 'seconde',
    'depuis', 'pendant', 'durant',

    // Divers
    'aucun', 'aucune', 'tout', 'tous', 'toute', 'toutes',
    'autre', 'autres', 'meme', 'memes', 'certain', 'certains',
    'plusieurs', 'chaque', 'quelque', 'quelques', 'peu', 'beaucoup',
    'rien', 'personne', 'quelquun',
    'non', 'oui', 'ok', 'okay', 'voici', 'voila',
    'numero', 'nom', 'type', 'version', 'nouveau', 'ancienne',
  ]);

  // Le résumé est prioritaire : on garde les mots dès 2 lettres (ex: "VPN", "AD")
  const resumeWords = cleanForKeywords(resume).split(' ').filter(w => w.length >= 2 && !stopwords.has(w));

  // La description est secondaire : on garde les mots significatifs de 4 lettres minimum
  const bodyWords = cleanForKeywords(description).split(' ').filter(w => w.length >= 4 && !stopwords.has(w));

  // Fusion, dédoublonnage et limitation à 10 mots-clés max
  return [...new Set([...resumeWords, ...bodyWords])].slice(0, 10);
}

function escapeCql(value) {
  return String(value || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

// Extraction des données du ticket
const ticket = $json;
const key = getValue(ticket, ['key']);
const resume = getValue(ticket, ['résumé', 'resume', 'summary']);
const description = getValue(ticket, ['description']);
const resolution = getValue(ticket, ['résolution', 'resolution', 'champ_resolution']);
const commentairesText = commentsToText(ticket.commentaires);

// Génération des mots-clés
const keywords = buildKeywords(resume, `${description} ${resolution} ${commentairesText}`);

// Court-circuit si pas assez de mots-clés significatifs
if (keywords.length < 2) {
  return {
    json: {
      ...ticket,
      key,
      text_for_analysis: `Résumé: ${resume}\nDescription: ${description}\nRésolution: ${resolution}\nCommentaires: ${commentairesText}`,
      confluence_keywords: [],
      confluence_cql: null
    }
  };
}

// Construction du CQL dynamique (5 meilleurs mots-clés)
const spaceFilter = 'space = "BDC"';
const searchTerms = keywords.slice(0, 5);
const cqlParts = searchTerms.map(term => `(title ~ "${escapeCql(term)}" OR text ~ "${escapeCql(term)}")`);
const cql = `${spaceFilter} AND type = page AND (${cqlParts.join(' OR ')})`;

return {
  json: {
    ...ticket,
    key,
    text_for_analysis: `Résumé: ${resume}\nDescription: ${description}\nRésolution: ${resolution}\nCommentaires: ${commentairesText}`,
    confluence_keywords: keywords,
    confluence_cql: cql
  }
};

function stripHtml(html) {
  return html
    .replace(/<[^>]+>/g, ' ')
    .replace(/&eacute;/g, 'é')
    .replace(/&agrave;/g, 'à')
    .replace(/&egrave;/g, 'è')
    .replace(/&acirc;/g, 'â')
    .replace(/&ocirc;/g, 'ô')
    .replace(/&ucirc;/g, 'û')
    .replace(/&ecirc;/g, 'ê')
    .replace(/&ccedil;/g, 'ç')
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&nbsp;/g, ' ')
    .replace(/&laquo;/g, '«')
    .replace(/&raquo;/g, '»')
    .replace(/&gt;/g, '>')
    .replace(/&lt;/g, '<')
    .replace(/\s+/g, ' ')
    .trim();
}

function estPageNavigation(contenu) {
  return contenu.includes('ac:structured-macro') && contenu.includes('recently-updated');
}

const tousLesTickets = $('Extract Search Keywords').all();

return $input.all().map((item, index) => {
  const confluenceResults = item.json.results || [];
  const ticketOrigine = tousLesTickets[index]?.json || {};

  let fichesConcatenees = "";
  let pagesFiltrees = [];

  if (confluenceResults.length === 0) {
    fichesConcatenees = "Aucune fiche trouvée.";
  } else {
    confluenceResults.forEach((page) => {
      const contenuBrut = page.body?.storage?.value || "";
      if (!contenuBrut || estPageNavigation(contenuBrut)) return;

      const contenu = stripHtml(contenuBrut);
      pagesFiltrees.push(page.title);
      fichesConcatenees += `\n\n--- FICHE : ${page.title} ---\n${contenu}`;
    });

    if (fichesConcatenees === "") {
      fichesConcatenees = "Aucune fiche pertinente trouvée.";
    }
  }

  return {
    json: {
      ...ticketOrigine,
      fiches_confluence: fichesConcatenees,
      debug_pages_trouvees: pagesFiltrees
    }
  };
});

return $input.all().map((item, index) => {
  let responseText = item.json.text;
  responseText = responseText.replace(/```json/gi, '').replace(/```/g, '').trim();
  const decision = JSON.parse(responseText);

  return {
    json: {
      ...$('Extract Search Keywords').all()[index].json,
      decision_ia: decision
    }
  };
});

// Collecte tous les tickets de la branche false en un seul objet
const tickets = $input.all().map(item => ({
  key: item.json.key,
  résumé: item.json.résumé,
  description: item.json.description,
  commentaires: item.json.commentaires,
  text_for_analysis: item.json.text_for_analysis
}));

return {
  json: {
    tickets_sans_fiche: tickets,
    nombre_tickets: tickets.length
  }
};

let responseText = $input.first().json.text;
responseText = responseText.replace(/```json/gi, '').replace(/```/g, '').trim();
const decision = JSON.parse(responseText);

// On récupère les données complètes des tickets concernés
const tousLesTickets = $('Aggregate Tickets Without KB').first().json.tickets_sans_fiche;
const ticketsConcernes = tousLesTickets.filter(t => 
  decision.tickets_concernes.includes(t.key)
);

return {
  json: {
    fiche_a_creer: decision.fiche_a_creer,
    problematique: decision.problematique,
    tickets_concernes: ticketsConcernes,
    justification: decision.justification
  }
};

return {
  json: {
    ...$json,
    fiches_confluence: "Aucune fiche trouvée.",
    debug_pages_trouvees: []
  }
};

const data = $input.first().json;

return {
  json: {
    action: "creer_fiche",
    problematique: data.problematique,
    justification: data.justification,
    tickets_sources: data.tickets_concernes
  }
};
